import{V as e,et as t,mt as n,tt as r}from"./chunks/framework.Bb5YUzRP.js";var i=JSON.parse(`{"title":"FAQ","description":"Frequently asked questions about Nodalite: Fetch API, package design, database integration, auth, WebSocket, OpenAPI, auto-discovery, and security. ","frontmatter":{"description":"Frequently asked questions about Nodalite: Fetch API, package design, database integration, auth, WebSocket, OpenAPI, auto-discovery, and security. "},"headers":[],"relativePath":"faq.md","filePath":"faq.md","lastUpdated":1784063781000}`),a={name:`faq.md`};function o(e,i,a,o,s,c){return n(),t(`div`,null,[...i[0]||=[r(`<h1 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to “FAQ”">​</a></h1><h2 id="why-fetch-api-instead-of-express-style-req-res" tabindex="-1">Why Fetch API instead of Express-style req/res? <a class="header-anchor" href="#why-fetch-api-instead-of-express-style-req-res" aria-label="Permalink to “Why Fetch API instead of Express-style req/res?”">​</a></h2><p>The standard <code>Request</code>/<code>Response</code> API is implemented natively by Node 18+, Bun, Deno, and Cloudflare Workers. Building on it means the same code runs everywhere without adapter rewrites. Express&#39;s <code>req</code>/<code>res</code> are tied to Node&#39;s <code>http</code> module, which is why it needs <code>serverless-http</code> for Lambda and can&#39;t run on Workers at all.</p><h2 id="why-so-many-packages-instead-of-one-big-framework" tabindex="-1">Why so many packages instead of one big framework? <a class="header-anchor" href="#why-so-many-packages-instead-of-one-big-framework" aria-label="Permalink to “Why so many packages instead of one big framework?”">​</a></h2><ol><li><strong>Tree-shaking</strong> — a Cloudflare Worker shouldn&#39;t pull in Node&#39;s <code>worker_threads</code> or Lambda types.</li><li><strong>Dependency isolation</strong> — <code>@nodalite/ml</code>&#39;s ONNX dep is ~270MB, but it&#39;s optional. Apps that don&#39;t touch ML pay nothing.</li><li><strong>Independent versioning</strong> — adapter fixes don&#39;t bump core.</li></ol><h2 id="can-i-use-nodalite-with-my-existing-database-orm" tabindex="-1">Can I use Nodalite with my existing database / ORM? <a class="header-anchor" href="#can-i-use-nodalite-with-my-existing-database-orm" aria-label="Permalink to “Can I use Nodalite with my existing database / ORM?”">​</a></h2><p>Yes. Nodalite has no built-in database layer. Use Drizzle, Prisma, Kysely, or any other data library directly in your handlers.</p><h2 id="can-i-use-nodalite-with-my-existing-auth-system" tabindex="-1">Can I use Nodalite with my existing auth system? <a class="header-anchor" href="#can-i-use-nodalite-with-my-existing-auth-system" aria-label="Permalink to “Can I use Nodalite with my existing auth system?”">​</a></h2><p>Yes. The <code>jwtAuth</code>/<code>signJwt</code> middleware is a convenience, not a requirement. You can use Passport.js, Auth0, Clerk, or any custom auth system — just handle it in your own middleware.</p><h2 id="how-does-nodalite-ml-protect-against-malicious-model-files" tabindex="-1">How does <code>@nodalite/ml</code> protect against malicious model files? <a class="header-anchor" href="#how-does-nodalite-ml-protect-against-malicious-model-files" aria-label="Permalink to “How does @nodalite/ml protect against malicious model files?”">​</a></h2><p><code>Model</code> enforces three safety checks by default when loading local files or URLs:</p><ol><li><strong>Path traversal protection</strong> — resolved file paths must stay inside <code>projectRoot</code> (default: <code>process.cwd()</code>).</li><li><strong>Size limits</strong> — models are capped at 50 MB by default (<code>maxBytes</code>).</li><li><strong>Format validation</strong> — only <code>.onnx</code>, <code>.bin</code>, and <code>.model</code> extensions are allowed; <code>.onnx</code> files are verified against the ONNX magic bytes.</li></ol><p>Override or disable any of these via <code>ModelOptions</code>. See <a href="/guides/ml-inference">ML Inference</a> for details.</p><h2 id="does-nodalite-work-with-typescript" tabindex="-1">Does Nodalite work with TypeScript? <a class="header-anchor" href="#does-nodalite-work-with-typescript" aria-label="Permalink to “Does Nodalite work with TypeScript?”">​</a></h2><p>Yes. Every package ships with <code>.d.ts</code> files. The <code>App</code> and <code>Context</code> classes are generic-typed for request-scoped store values.</p><h2 id="does-nodalite-work-with-esm-and-cjs" tabindex="-1">Does Nodalite work with ESM and CJS? <a class="header-anchor" href="#does-nodalite-work-with-esm-and-cjs" aria-label="Permalink to “Does Nodalite work with ESM and CJS?”">​</a></h2><p>Yes. Every package is dual-published with both <code>import</code> and <code>require</code> entry points via the <code>exports</code> map in <code>package.json</code>.</p><h2 id="is-there-a-websocket-solution" tabindex="-1">Is there a WebSocket solution? <a class="header-anchor" href="#is-there-a-websocket-solution" aria-label="Permalink to “Is there a WebSocket solution?”">​</a></h2><p>Yes — <a href="/api/ws"><code>@nodalite/ws</code></a> provides a runtime-agnostic WebSocket server with path-based routing, rooms, heartbeat, and per-connection typed state. It includes adapters for Node.js, Cloudflare Workers, Deno, Bun, and AWS Lambda. On Node.js, it can use the <code>ws</code> library or a zero-dependency RFC 6455 fallback.</p><h2 id="what-s-deliberately-not-included" tabindex="-1">What&#39;s deliberately NOT included? <a class="header-anchor" href="#what-s-deliberately-not-included" aria-label="Permalink to “What&#39;s deliberately NOT included?”">​</a></h2><ul><li><strong>No ORM/database layer</strong> — use Drizzle, Prisma, Kysely directly</li><li><strong>No DI container</strong> — <code>c.set</code>/<code>c.get</code> with a <code>Map</code> is sufficient; bring <code>tsyringe</code> or <code>awilix</code> if you need more</li><li><strong>No file upload handling</strong> — use Busboy, formidable, or any multipart library directly</li></ul><h2 id="what-is-the-query-method" tabindex="-1">What is the QUERY method? <a class="header-anchor" href="#what-is-the-query-method" aria-label="Permalink to “What is the QUERY method?”">​</a></h2><p><code>QUERY</code> (<a href="https://datatracker.ietf.org/doc/html/rfc10008" target="_blank" rel="noreferrer">RFC 10008</a>) is an HTTP method that is <strong>safe and idempotent</strong> like <code>GET</code>, but also accepts a request body. It&#39;s useful for search or filter operations where the query is too complex for URL parameters:</p><div class="language-ts"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">app.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">query</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;/search&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#c62739;--shiki-dark:#F97583;">async</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span><span style="--shiki-light:#c13617;--shiki-dark:#FFAB70;">c</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#c62739;--shiki-dark:#F97583;">=&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#c62739;--shiki-dark:#F97583;">  const</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">filters</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">sort</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">pagination</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> } </span><span style="--shiki-light:#c62739;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#c62739;--shiki-dark:#F97583;"> await</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> c.req.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">json</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">();</span></span>
<span class="line"><span style="--shiki-light:#c62739;--shiki-dark:#F97583;">  const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> results</span><span style="--shiki-light:#c62739;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#c62739;--shiki-dark:#F97583;"> await</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> db.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">search</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(filters, sort, pagination);</span></span>
<span class="line"><span style="--shiki-light:#c62739;--shiki-dark:#F97583;">  return</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> c.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">json</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">({ results });</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">});</span></span></code></pre></div><p>Use <code>QUERY</code> when the operation should never cause side effects but needs a structured body. Use <code>POST</code> when the operation creates or modifies resources.</p><h2 id="when-should-i-use-auto-discovery" tabindex="-1">When should I use auto-discovery? <a class="header-anchor" href="#when-should-i-use-auto-discovery" aria-label="Permalink to “When should I use auto-discovery?”">​</a></h2><p>Use <code>discover()</code> when your project has many route files and you want to avoid manually importing each one. It scans a directory, imports every route file, and registers them automatically — subdirectories become route groups with prefix detection via <code>_prefix.ts</code> files.</p><p>It&#39;s a good fit for medium-to-large APIs with dozens of route files. For small projects with a handful of routes, explicit imports in <code>app.ts</code> are simpler and more transparent.</p><p>Auto-discovery uses dynamic <code>import()</code> and works on Node, Bun, and Deno. It&#39;s <strong>not suitable for bundled edge runtimes</strong> (Cloudflare Workers) — use static imports there.</p><h2 id="are-the-in-memory-stores-production-ready" tabindex="-1">Are the in-memory stores production-ready? <a class="header-anchor" href="#are-the-in-memory-stores-production-ready" aria-label="Permalink to “Are the in-memory stores production-ready?”">​</a></h2><p>No. <code>MemoryRateLimitStore</code>, <code>MemoryApiKeyStore</code>, and <code>MemorySessionStore</code> are single-process only — each instance has its own isolated memory. They&#39;re intended for development and testing.</p><p>For production, implement the corresponding store interface against a shared datastore:</p><table tabindex="0"><thead><tr><th>Store</th><th>Interface</th><th>Production options</th></tr></thead><tbody><tr><td>Rate limiting</td><td><code>RateLimitStore</code></td><td>Redis, Upstash, DynamoDB</td></tr><tr><td>API keys</td><td><code>ApiKeyStore</code></td><td>Redis, Postgres, DynamoDB</td></tr><tr><td>Sessions</td><td><code>SessionStore</code></td><td>Redis, DynamoDB, Postgres</td></tr></tbody></table><p>All memory stores include cleanup timers and <code>destroy()</code> methods to prevent leaks in long-running processes.</p><h2 id="which-security-middleware-do-i-need" tabindex="-1">Which security middleware do I need? <a class="header-anchor" href="#which-security-middleware-do-i-need" aria-label="Permalink to “Which security middleware do I need?”">​</a></h2><table tabindex="0"><thead><tr><th>Threat</th><th>Middleware</th><th>When to use</th></tr></thead><tbody><tr><td>CSRF</td><td><code>csrf()</code></td><td>Browser-facing forms or cookie-based auth</td></tr><tr><td>XSS (stored)</td><td><code>xssSanitize()</code></td><td>User content rendered as HTML later</td></tr><tr><td>SSRF</td><td><code>ssrfGuard()</code></td><td>Routes that fetch user-supplied URLs</td></tr><tr><td>Brute force</td><td><code>rateLimit()</code></td><td>Any public endpoint</td></tr><tr><td>Unauthorized access</td><td><code>jwtAuth()</code> or <code>apiKey()</code></td><td>Protecting API routes</td></tr><tr><td>IP abuse</td><td><code>ipGuard()</code></td><td>Admin panels, geo-restricted APIs</td></tr><tr><td>Wrong content type</td><td><code>contentTypeGuard()</code></td><td>API endpoints expecting specific payloads</td></tr><tr><td>Hanging requests</td><td><code>requestTimeout()</code></td><td>Slow backends, external API calls</td></tr><tr><td>Session hijacking</td><td><code>sessions()</code></td><td>Cookie-based auth (alternative to JWT)</td></tr><tr><td>Missing trace context</td><td><code>requestId()</code></td><td>Distributed systems, log correlation</td></tr></tbody></table><p>Not every API needs all of them. Start with <code>rateLimit</code>, <code>cors</code>, <code>securityHeaders</code>, and <code>bodyLimit</code> — add the rest as your threat model requires.</p><h2 id="can-i-contribute" tabindex="-1">Can I contribute? <a class="header-anchor" href="#can-i-contribute" aria-label="Permalink to “Can I contribute?”">​</a></h2><p>Yes! See <a href="https://github.com/AkkilMG/nodalite/blob/main/CONTRIBUTING.md" target="_blank" rel="noreferrer">CONTRIBUTING.md</a>.</p><h2 id="license" tabindex="-1">License <a class="header-anchor" href="#license" aria-label="Permalink to “License”">​</a></h2><p>MIT — see the <a href="https://github.com/AkkilMG/nodalite/blob/main/LICENSE" target="_blank" rel="noreferrer">LICENSE</a> file. Copyright © 2026-present Akkil M G.</p>`,41)]])}var s=e(a,[[`render`,o]]);export{i as __pageData,s as default};